class Solution {
public:
    int wordCount(vector<string>& startWords, vector<string>& targetWords) {
        int count = 0;
        unordered_set<string> startSet(startWords.begin(), startWords.end());
        for (const auto& target : targetWords) {
            bool found = false;
            for (const auto& start : startWords) {
                if (start.size() + 1 == target.size()) {
                    unordered_set<char> startChars(start.begin(), start.end());
                    unordered_set<char> targetChars(target.begin(), target.end());
                    if (startChars.size() == targetChars.size() - 1) {
                        bool isSubset = true;
                        for (const auto& c : startChars) {
                            if (targetChars.find(c) == targetChars.end()) {
                                isSubset = false;
                                break;
                            }
                        }
                        if (isSubset) {
                            found = true;
                            break;
                        }
                    }
                }
            }
            if (found) {
                count++;
            }
        }
        return count;
    }
};
